Here is a C++ program to read a text file line by line and count the occurrences of a specific word:

```cpp
#include <iostream>
#include <fstream>
#include <string>

using namespace std;

int main() {
  ifstream inFile;
  string line;
  string searchWord;
  int count = 0;

  inFile.open("input.txt");

  if(!inFile) {
    cerr << "Unable to open file";
    exit(1);  
  }

  cout << "Enter the word to search for: ";
  cin >> searchWord;

  while(getline(inFile, line)) {
    int pos = 0;
    while((pos = line.find(searchWord, pos)) != string::npos) {
      count++;
      pos += searchWord.length();
    }
  }

  cout << "The word " << searchWord << " appears " << count << " times.";

  inFile.close();

  return 0;
}
```

The key steps are:

1. Open the input text file using an ifstream object.

2. Read the file line by line using getline() in a while loop. 

3. For each line, use find() to search for the word and increment count when found.

4. After the loop, print out the total count.

5. Close the file.

